import{_ as s,o as a,c as p,ag as e}from"./chunks/framework.NIzFHKo_.js";const u=JSON.parse('{"title":"Data Flow","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/20_structure/50_data_flow.md","filePath":"10_core/20_structure/50_data_flow.md"}'),l={name:"10_core/20_structure/50_data_flow.md"};function i(c,n,t,o,r,d){return a(),p("div",null,[...n[0]||(n[0]=[e(`<h1 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data Flow&quot;">​</a></h1><h2 id="canonical-ingestion-flow" tabindex="-1">Canonical Ingestion Flow <a class="header-anchor" href="#canonical-ingestion-flow" aria-label="Permalink to &quot;Canonical Ingestion Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SOURCE FILE</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>DEVICE DROP ZONE / ASSIGNED WATCH PATH</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>LOCAL AGENT DETECT</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>RESOLVE DOMAIN (namespace + prefix lookup)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>REGISTER IN QiARCHIVE</span></span>
<span class="line"><span>  - assign canonical ID (UUID/ULID)</span></span>
<span class="line"><span>  - assign short visible code (Q + 6 hex)</span></span>
<span class="line"><span>  - normalize filename: {domain}_{name}_{QXXXXXX}.ext</span></span>
<span class="line"><span>  - calculate checksum</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>EXTRACT / INSPECT</span></span>
<span class="line"><span>  - detect MIME type</span></span>
<span class="line"><span>  - choose parser</span></span>
<span class="line"><span>  - extract text</span></span>
<span class="line"><span>  - OCR if needed</span></span>
<span class="line"><span>  - store extraction method + raw text</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>ENRICH METADATA</span></span>
<span class="line"><span>  - infer document type</span></span>
<span class="line"><span>  - extract entities</span></span>
<span class="line"><span>  - tag confidence values</span></span>
<span class="line"><span>  - assign semantic metadata</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>CHUNK</span></span>
<span class="line"><span>  - split text deterministically</span></span>
<span class="line"><span>  - assign chunk indices</span></span>
<span class="line"><span>  - link chunks to archive_id</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>EMBED (local)</span></span>
<span class="line"><span>  - generate embedding vectors</span></span>
<span class="line"><span>  - push to pgvector (qiarchive.archive_chunks)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>INDEX</span></span>
<span class="line"><span>  - update search index</span></span>
<span class="line"><span>  - update qigraph.master_index if applicable</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>ROUTE / REVIEW / ACT</span></span>
<span class="line"><span>  - suggest route based on doc type + confidence</span></span>
<span class="line"><span>  - human review or auto-confirm</span></span>
<span class="line"><span>  - finalize placement</span></span>
<span class="line"><span>  - update archive record</span></span></code></pre></div><h2 id="rag-ai-query-flow" tabindex="-1">RAG / AI Query Flow <a class="header-anchor" href="#rag-ai-query-flow" aria-label="Permalink to &quot;RAG / AI Query Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>USER QUERY</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>Metadata filter in Postgres (Supabase)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>Semantic retrieval in pgvector</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼ (optional)</span></span>
<span class="line"><span>Graph expansion in Neo4j / qigraph</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>Assemble evidence with provenance references</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>Generate answer citing archive_id / chunk_id / entity_id</span></span></code></pre></div><h2 id="infrastructure-edge-ingress-local-node-hosting" tabindex="-1">Infrastructure Edge Ingress (Local Node Hosting) <a class="header-anchor" href="#infrastructure-edge-ingress-local-node-hosting" aria-label="Permalink to &quot;Infrastructure Edge Ingress (Local Node Hosting)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PUBLIC REQUEST (Internet)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>EDGE PROVIDER (DNS / Policy / Tunnel Endpoint)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>OUTBOUND TUNNEL CONNECTOR (Local Node)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>LOCAL REVERSE PROXY (Routing / Auth Check)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>TARGET SERVICE (App Container / Webhook)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>INTERNAL DATA SERVICE (Postgres / Vector DB)</span></span></code></pre></div><h2 id="flow-invariants" tabindex="-1">Flow Invariants <a class="header-anchor" href="#flow-invariants" aria-label="Permalink to &quot;Flow Invariants&quot;">​</a></h2><ul><li>Every record entering the system carries a canonical ID <strong>before</strong> extraction begins</li><li>Derived layers (graph, vector, AI) only receive data <strong>after</strong> the archive ID is assigned</li><li>Failure at any stage is visible, stateful, and retryable — it never silently drops data</li><li><strong>Provenance</strong>: Every ingest must carry <code>source_device_id</code>, <code>source_agent_id</code>, <code>source_path</code>, and <code>ingest_mode</code> because ingestion happens across nodes.</li></ul>`,9)])])}const g=s(l,[["render",i]]);export{u as __pageData,g as default};
